import boto3
import os
import subprocess
from flask import Flask, request, jsonify
from selenium import webdriver
from selenium.webdriver.chrome.options import Options
from werkzeug.utils import secure_filename

app = Flask(__name__)

# AWS S3 Configuration
S3_BUCKET = 'your-s3-bucket-name'
S3_REGION = 'your-s3-region'
s3_client = boto3.client('s3', region_name=S3_REGION)

# Chrome Driver Configuration
CHROME_DRIVER_PATH = '/path/to/chromedriver'
CHROME_BINARY_PATH = '/path/to/headless-chrome'

def take_screenshot(url, output_file):
    options = Options()
    options.binary_location = CHROME_BINARY_PATH
    options.add_argument('--headless')
    options.add_argument('--no-sandbox')
    options.add_argument('--disable-dev-shm-usage')
    driver = webdriver.Chrome(executable_path=CHROME_DRIVER_PATH, options=options)
    driver.set_window_size(1280, 720)
    driver.get(url)
    driver.save_screenshot(output_file)
    driver.quit()

def upload_to_s3(file_name, bucket, object_name=None):
    if object_name is None:
        object_name = file_name
    s3_client.upload_file(file_name, bucket, object_name)
    return f"https://{bucket}.s3.{S3_REGION}.amazonaws.com/{object_name}"

@app.route('/screenshot', methods=['POST'])
def screenshot():
    url = request.json.get('url')
    if not url:
        return jsonify({'error': 'URL is required'}), 400

    try:
        file_name = secure_filename(f"{url.replace('http://', '').replace('https://', '').replace('/', '_')}.png")
        take_screenshot(url, file_name)
        s3_url = upload_to_s3(file_name, S3_BUCKET)
        os.remove(file_name)
        return jsonify({'s3_url': s3_url}), 200
    except Exception as e:
        return jsonify({'error': str(e)}), 500

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000)